import { RadioGroup as RadioGroupPrimitive } from "@base-ui/react/radio-group";
import { createStyleContext } from "@/registry/bare/lib/create-style-context";
import { createPropSplitter } from "@/registry/bare/lib/split-variant-props";
import { radioStyles } from "./styles";
import type { VariantProps } from "@/registry/bare/lib/tv.config";

type RadioStyles = ReturnType<typeof radioStyles>;
type RadioVariantProps = VariantProps<typeof radioStyles>;

const { StyleContext, useStyles } = createStyleContext<RadioStyles>("Radio");
const splitProps = createPropSplitter(radioStyles);

export { useStyles as useRadioStyles };

interface RadioRootProps extends RadioGroupPrimitive.Props, RadioVariantProps {
  className?: string;
  styles?: RadioStyles;
}

export function RadioRoot(props: RadioRootProps) {
  const [variantProps, { className, styles, ...htmlProps }] = splitProps(props);
  const s = styles ?? radioStyles(variantProps);
  return (
    <StyleContext value={s}>
      <RadioGroupPrimitive {...htmlProps} className={s.root({ class: className })} data-slot="radio" />
    </StyleContext>
  );
}

import { Radio as RadioPrimitive } from "@base-ui/react/radio";
import { useRadioStyles } from "./radio-root";

interface RadioItemProps extends RadioPrimitive.Root.Props {
  className?: string;
}

export function RadioItem({ className, ...props }: RadioItemProps) {
  const styles = useRadioStyles();
  return <RadioPrimitive.Root {...props} className={styles.item({ class: className })} data-slot="radio-item" />;
}

import { Radio as RadioPrimitive } from "@base-ui/react/radio";
import { useRadioStyles } from "./radio-root";

interface RadioIndicatorProps extends RadioPrimitive.Indicator.Props {
  className?: string;
}

export function RadioIndicator({ className, ...props }: RadioIndicatorProps) {
  const styles = useRadioStyles();
  return (
    <RadioPrimitive.Indicator
      {...props}
      className={styles.indicator({ class: className })}
      data-slot="radio-indicator"
    />
  );
}

import { tv } from "@/registry/bare/lib/tv.config";

export const radioStyles = tv({
  slots: {
    root: [""],
    item: [""],
    indicator: [""],
  },
});

export { RadioRoot as Root } from "./radio-root";
export { RadioItem as Item } from "./radio-item";
export { RadioIndicator as Indicator } from "./radio-indicator";
